// Synthesize 5 leads — pretend these arrived from a CRM webhook.
// This node is not the bug. It outputs 5 items, exactly as expected.

return [
  { json: { id: 1, name: "Acme Corp",         email: "founder@acme.test",   country: "US" } },
  { json: { id: 2, name: "Globex Industries", email: "ops@globex.test",     country: "DE" } },
  { json: { id: 3, name: "Initech Systems",   email: "it@initech.test",     country: "CA" } },
  { json: { id: 4, name: "Umbrella Ltd",      email: "biz@umbrella.test",   country: "UK" } },
  { json: { id: 5, name: "Hooli Holdings",    email: "people@hooli.test",   country: "US" } }
];

// ─────────────────────────────────────────────────────────────
// BUG: this Code node only ever processes the FIRST item.
//
//   $input.all() returns every item from the previous node (5 leads),
//   but we grab items[0] and return just that — so 4 leads silently
//   disappear.
//
//   At a glance, this looks like it's processing "the current lead."
//   It's not — it's hard-coding the first one.
//
//   You will see this same shape on the n8n forum constantly:
//     const lead = $input.first().json;
//     const lead = items[0].json;
//     const lead = $json;          // (in 'Run Once for All Items' mode
//                                  //   $json is also items[0] — same trap)
//
// HOW TO SEE THE BUG:
//   1. Run the workflow with the "Test workflow" button.
//   2. Click this node — the output panel shows 1 item, not 5.
//   3. Compare with the upstream node "Generate 5 Leads" — 5 items.
// ─────────────────────────────────────────────────────────────

const items = $input.all();
const lead  = items[0].json;   // ← THE BUG

lead.processedAt = new Date().toISOString();
lead.status      = "processed";

return [{ json: lead }];
